function randomInt(max) {
  const upper = Math.floor(Number(max) || 0);
  if (upper <= 0) return 0;
  if (window.crypto?.getRandomValues) {
    const values = new Uint32Array(1);
    const limit = Math.floor(0x100000000 / upper) * upper;
    do {
      window.crypto.getRandomValues(values);
    } while (values[0] >= limit);
    return values[0] % upper;
  }
  return Math.floor(Math.random() * upper);
}

function randomToken(length, alphabet) {
  const chars = String(alphabet || 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789');
  const size = Math.max(1, Number(length) || 1);
  let out = '';
  for (let i = 0; i < size; i++) out += chars[randomInt(chars.length)];
  return out;
}

function makePlaceholderId() {
  return `ph_${randomToken(12, 'abcdefghijklmnopqrstuvwxyz0123456789')}`;
}

function getPrimaryAvatar(figure, preferredMood) {
  if (!figure || !figure.avatars) return null;
  if (preferredMood && figure.avatars[preferredMood]) return figure.avatars[preferredMood];
  return Object.values(figure.avatars).find(Boolean) || null;
}

function buildAvatarEmotes(figure) {
  if (!figure || !figure.avatars) return [];
  const seen = new Set();
  return Object.entries(figure.avatars)
    .filter(([, src]) => !!src)
    .filter(([, src]) => {
      if (seen.has(src)) return false;
      seen.add(src);
      return true;
    })
    .map(([label, src]) => ({
      img: src,
      label: String(label || 'Avatar').replace(/[_-]+/g, ' ')
    }));
}

function buildBuiltinCommentCharacter(id, figure, preferredMood, overrides = {}) {
  return {
    id: `builtin:${id}`,
    name: overrides.name || figure?.name || 'Unbekannt',
    title: overrides.title || figure?.title || '',
    portrait: overrides.portrait || getPrimaryAvatar(figure, preferredMood),
    emotes: overrides.emotes || buildAvatarEmotes(figure),
  };
}

