function ph(title, type, who, icon) {
  const slug = String(title || "ausstehend")
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '') || 'ausstehend';
  return {
    id: `ph-${slug}`,
    title: title || "Ausstehend",
    subtitle: "Dokumentation in Vorbereitung",
    type: type || "Unbekannt",
    category: "—",
    image: null, stamp: "UNBEKANNT",
    description: "Dieser Eintrag befindet sich noch in Bearbeitung. Yvain Seldryn und Annarietta Schönbergen arbeiten an der Vervollständigung des Codex.",
    stats: [],
    commentator: who,
    commentatorMood: who === YVAIN ? "ernst" : "freundlich",
    commentText: who === YVAIN
      ? "Die Aufzeichnungen zu diesem Eintrag sind noch unvollständig. Wir werden diesen Codex über Aleria mit gebührender Sorgfalt vervollständigen."
      : "Dieser Eintrag wartet noch auf seine Vollendung — aber ich versichere Euch, das Beste kommt noch, wie man so schön sagt.",
    quote: null,
    locked: true,
    icon: "",
  };
}

